import{_ as t,o as s,c as n,O as l}from"./chunks/framework.92cbe775.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"materials/pitch.md","filePath":"materials/pitch.md","lastUpdated":1776005512000}'),d={name:"materials/pitch.md"};function r(e,a,i,p,c,_){return s(),n("div",null,a[0]||(a[0]=[l('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Pitch Outline</p><h1>介绍提纲</h1><div class="brand-hero__panel"><span class="brand-pill">Talking Point</span><strong>真正有效的介绍，不是先堆技术名词，而是先判断对方现在处在免费线、本地脚本位、正式团队协作，还是企业项目交付哪一层。</strong><p>先把当前入口路径讲对，再补平台定位、问题定义和交付方式，才不会把个人扩容、标准团队版和企业交付混成一套说法。</p></div><p class="brand-lead"> 这一页集中说明 ExecGov 的核心介绍结构，覆盖平台定位、问题定义、四层路径和当前落地重点。 适合用于第一次接触、介绍开场和正式沟通前统一口径。 </p><div class="brand-chip-list"><span class="brand-chip">30 秒版本</span><span class="brand-chip">3 分钟版本</span><span class="brand-chip">简短结构</span><span class="brand-chip">适合沟通</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./value.html">看价值说明</a><a class="cta-button" href="../product/index.html">看产品概览</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // PITCH OUTLINE</span><span>MAT 02</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">problem</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">scripts_exist</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">entry_is_fragmented</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">platform</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">intent_routing</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">controlled_execution</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">path</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">free</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">local_slots</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">team_saas</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">private_delivery</span></span></div><div class="matrix-panel__callout">GOOD PITCHES REDUCE CONFUSION FAST</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">format</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">30s</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">format</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">3min</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">format</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">deck</span></span></div></div></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">30 Seconds</p><h2>30 秒版本怎么讲</h2><p>ExecGov 不是再给团队加一个聊天壳，而是帮你把那些散装的、危险的脚本管起来。谁在什么时候执行了什么、结果如何，都有记录；高风险动作先确认。当前最先落地、最成熟的第一种能力载体，就是 Python 脚本。</p></article><article class="brand-card"><p class="brand-kicker">3 Minutes</p><h2>3 分钟版本怎么讲</h2><p>先讲问题：很多团队已经有脚本、接口和流程，但它们散落在共享盘、服务器和个人电脑里，执行风险高、交接成本高。再讲平台：AI 负责理解需求和推荐能力，平台负责边界、确认、执行和审计。最后讲路径：个人先走免费线，持续使用但还没进入正式协作时走本地脚本位增购，真正进入多人协作时走团队版月租 / 年租正式租户入口，涉及更强隔离、内网或正式项目时再转企业交付。现在更重要的是先把真实问题解决好，而不是把路线讲得很远。</p></article></section><section class="brand-card"><p class="brand-kicker">Entry First</p><h2>先判断对方在哪一层，再决定怎么讲</h2><table><thead><tr><th>当前对象</th><th>先讲什么</th><th>不要怎么讲</th><th>建议入口</th></tr></thead><tbody><tr><td>第一次接触平台的人</td><td>先讲平台定位、痛点和免费线体验价值</td><td>不要一开始就讲企业交付和复杂定制</td><td><a href="../guide/getting-started.html">快速开始</a></td></tr><tr><td>已经在个人空间持续接脚本的人</td><td>先讲本地脚本位扩容和轻量增购</td><td>不要把个人扩容说成正式团队版</td><td><a href="./membership-benefits-pricing.html">会员权益与价格说明</a></td></tr><tr><td>准备进入多人协作的团队</td><td>先讲团队版月租 / 年租正式租户入口</td><td>不要把共享 SaaS 路径讲成默认私有化交付</td><td><a href="../product/personal-billing-membership.html">支付与会员说明</a></td></tr><tr><td>需要更强隔离、内网或正式项目验收的客户</td><td>先讲部署、交付边界和企业项目节奏</td><td>不要继续沿用标准会员页口径</td><td><a href="../product/deployment.html">部署方式</a> / <a href="./service-packages.html">启动方式 / 服务包</a></td></tr></tbody></table></section><section class="brand-card"><p class="brand-kicker">Deck Structure</p><h2>简短介绍结构可以怎么排</h2><table><thead><tr><th>页次</th><th>标题</th><th>这一页要讲清什么</th><th>建议画面</th></tr></thead><tbody><tr><td>01</td><td>封面页</td><td>讲清平台名字和一句话定位</td><td>平台主视觉 + 口号</td></tr><tr><td>02</td><td>我们在解决什么问题</td><td>很多企业已有脚本、接口和流程，但没有统一执行入口</td><td>分散脚本汇入一个平台入口</td></tr><tr><td>03</td><td>平台是什么</td><td>不是普通聊天系统，而是可信执行平台</td><td>上层对话、下层能力与权限的分层图</td></tr><tr><td>04</td><td>核心交付模式</td><td>标准 SaaS 正式租户入口和企业单租户交付是两条现实路线</td><td>共享 SaaS 与企业交付的双路径示意</td></tr><tr><td>05</td><td>为什么客户愿意买单</td><td>客户买的不是页面，而是效率、隔离和可持续更新</td><td>人工操作 vs 平台执行对比图</td></tr><tr><td>06</td><td>执行闭环</td><td>用户需求 -&gt; AI 理解 -&gt; 推荐能力 -&gt; 确认 -&gt; 执行 -&gt; 结果</td><td>横向流程图</td></tr><tr><td>07</td><td>当前落地能力</td><td>多租户、能力接入、智能大脑、热更新、CLI 已有真实基础</td><td>能力卡片墙</td></tr><tr><td>08</td><td>安全与隔离优势</td><td>平台强项不是更会说，而是只能在授权范围内做事</td><td>租户、权限、确认、审计边界图</td></tr><tr><td>09</td><td>当前阶段与下一步</td><td>先把 1.0 交付做稳，再决定哪些部分值得进入 2.0 标准化扩展</td><td>版本路线图</td></tr><tr><td>10</td><td>结尾页</td><td>收束成一句明确价值表达</td><td>主视觉 + 联系方式</td></tr></tbody></table></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Do Say</p><h2>对外表达要点</h2><ul class="brand-list"><li>先判断对方当前属于免费线、本地脚本位、团队版还是企业交付</li><li>它把分散脚本、接口和流程收进统一入口</li><li>AI 在规则内推荐和触发能力</li><li>平台强调租户隔离、确认执行和审计留痕</li><li>标准团队版当前由共享 SaaS 前端承接，企业项目再进入更强隔离交付</li><li>先讲当前可用能力，再讲后续扩展方向</li></ul></article><article class="brand-card"><p class="brand-kicker">Current Stage</p><h2>当前阶段适合这样理解</h2><ul class="brand-list"><li>平台当前最成熟的执行资产是 Python 脚本</li><li><code>execgov-cli</code> 适合本地接入和前期验证，常驻 Agent 能力在持续完善</li><li>正式客户交付当前分成共享 SaaS 正式租户入口和企业单租户交付两条现实路线</li><li>public 超管侧已先落下一版 HTTP 能力接入样板，验证第二种能力如何进入治理链路</li><li>更标准的小团队使用方式会继续收敛，当前由 <code>tenant_1003+</code> / <code>exec-gov-common</code> 承接共享 SaaS 前端</li><li>更多能力类型会逐步接入统一治理链路</li></ul></article><article class="brand-card"><p class="brand-kicker">Demo Order</p><h2>讲解顺序</h2><ol class="brand-list"><li>先判断对方属于免费线、本地脚本位、团队版还是企业交付</li><li>再讲问题和平台定义</li><li>再展示对应体验路径或团队升级路径</li><li>再讲客户流程 / 交付和隔离边界</li><li>最后按需要补 CLI 或部署方式</li></ol></article></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>价值判断可继续在下一页展开</h2><p class="brand-lead">继续阅读价值说明，可以把老板、业务负责人和交付负责人最关心的问题一起收口。</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./value.html"><span>Value</span><strong>价值说明</strong></a><a class="brand-link-card" href="../product/customer-flow.html"><span>Delivery</span><strong>客户流程 / 交付</strong></a><a class="brand-link-card" href="../product/editions.html"><span>Roadmap</span><strong>版本路线</strong></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead</span><strong>沟通真实场景</strong></a></div></div></section></div>',1)]))}const h=t(d,[["render",r]]);export{m as __pageData,h as default};
